function Get-ActiveEmployees {
    # Reads a CSV file and returns only rows where status is "active".
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [string]$Path
    )

    if (-not (Test-Path $Path)) {
        throw "CSV file '$Path' does not exist."
    }

    Import-Csv $Path | Where-Object { $_.status -eq "active" }
}

